#include <stdio.h>
#include <string.h>
#include <stdbool.h>

bool match(const char *s, const char *p) {
    int i = 0, j = 0;
    int star = -1, ss = 0;
    int n = strlen(s), m = strlen(p);
    while (i < n) {
        if (j < m && (p[j] == '?' || p[j] == s[i])) {
            i++; j++;
        } else if (j < m && p[j] == '*') {
            star = j;
            ss = i;
            j++;
        } else if (star != -1) {
            j = star + 1;
            ss++;
            i = ss;
        } else {
            return false;
        }
    }
    while (j < m && p[j] == '*') j++;
    return j == m;
}

int main() {
    int t; if (scanf("%d", &t)!=1) return 0;
    while (t--) {
        int N, Q; scanf("%d %d", &N, &Q);
        char words[55000][26];
        for (int i = 0; i < N; ++i) scanf("%s", words[i]);
        char pattern[26];
        for (int qi = 0; qi < Q; ++qi) {
            scanf("%s", pattern);
            int cnt = 0;
            for (int i = 0; i < N; ++i) if (match(words[i], pattern)) cnt++;
            printf("%s %d\n", pattern, cnt);
        }
        if (t) printf("\n");
    }
    return 0;
}

