import java.io.*;
import java.util.*;

public class Main {
    private static boolean match(String s, String p) {
        int i = 0, j = 0;
        int star = -1, ss = 0;
        int n = s.length(), m = p.length();
        while (i < n) {
            if (j < m && (p.charAt(j) == '?' || p.charAt(j) == s.charAt(i))) {
                i++; j++;
            } else if (j < m && p.charAt(j) == '*') {
                star = j;
                ss = i;
                j++;
            } else if (star != -1) {
                j = star + 1;
                ss++;
                i = ss;
            } else {
                return false;
            }
        }
        while (j < m && p.charAt(j) == '*') j++;
        return j == m;
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        for (int tc = 0; tc < T; ++tc) {
            String line;
            // skip possible blank lines
            while ((line = br.readLine()) != null && line.trim().isEmpty()) {}
            st = new StringTokenizer(line);
            int N = Integer.parseInt(st.nextToken());
            int Q = Integer.parseInt(st.nextToken());
            String[] dict = new String[N];
            for (int i = 0; i < N; ++i) dict[i] = br.readLine().trim();
            for (int q = 0; q < Q; ++q) {
                String pat = br.readLine().trim();
                int cnt = 0;
                for (String w : dict) if (match(w, pat)) cnt++;
                out.append(pat).append(' ').append(cnt).append('\n');
            }
            if (tc != T-1) out.append('\n');
        }
        System.out.print(out.toString());
    }
}

