#!/usr/bin/env python3
import sys

def match(s: str, p: str) -> bool:
    i = j = 0
    star = -1
    ss = 0
    n, m = len(s), len(p)
    while i < n:
        if j < m and (p[j] == '?' or p[j] == s[i]):
            i += 1
            j += 1
        elif j < m and p[j] == '*':
            star = j
            ss = i
            j += 1
        elif star != -1:
            j = star + 1
            ss += 1
            i = ss
        else:
            return False
    while j < m and p[j] == '*':
        j += 1
    return j == m

def solve():
    data = sys.stdin.read().splitlines()
    idx = 0
    t = int(data[idx].strip()); idx += 1
    out_lines = []
    for _ in range(t):
        # skip blank lines
        while idx < len(data) and data[idx].strip() == '':
            idx += 1
        N, Q = map(int, data[idx].split()); idx += 1
        words = [data[idx + i].strip() for i in range(N)]
        idx += N
        for _ in range(Q):
            pat = data[idx].strip(); idx += 1
            cnt = sum(1 for w in words if match(w, pat))
            out_lines.append(f"{pat} {cnt}")
        if _ != t-1:
            out_lines.append('')
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

